sql:
SELECT trial_id, COUNT(DISTINCT device_id) AS num_unique_devices
FROM data_points
GROUP BY trial_id;

external_knowledge:
- 'top performers' refers to the participants with the highest average geographic variability; 
- 'still involved in the activities' means the participants whose status is 'active';
- 'average geographic variability' is represented by the `avg_geo_diff` calculated from geographic differences.

sql:
SELECT name
FROM participants
WHERE participant_id NOT IN (SELECT participant_id FROM data_points);

SELECT t.trial_id, t.trial_name, dp.date, dp.time, dp.latitude, dp.longitude, dp.altitude, dp.milliseconds_since_trial_start, dp.data_quality
FROM trials t
JOIN data_points dp ON t.trial_id = dp.trial_id;

SELECT COUNT(*) AS TotalRows
FROM analytics
ORDER BY start_date, end_date;

external_knowledge:
- "garden" refers to the collection of trials;
- "blossoms" symbolically represents the active trials;
- "saplings" metaphorically refers to the active participants;
- "type of soil" means the type of trial;
- "planting date" is the start date of the trial.
